3282	static JSValue
3283	ngx_qjs_ext_shared_dict_clear(JSContext *cx, JSValueConst this_val,
3284	    int argc, JSValueConst *argv)
3285	{
3286	    ngx_rbtree_t       *rbtree;
3287	    ngx_js_dict_t      *dict;
3288	    ngx_shm_zone_t     *shm_zone;
3289	    ngx_rbtree_node_t  *rn, *next;
3290	
3291	    shm_zone = JS_GetOpaque(this_val, NGX_QJS_CLASS_ID_SHARED_DICT);
3292	    if (shm_zone == NULL) {
3293	        return JS_ThrowTypeError(cx, "\"this\" is not a shared dict");
3294	    }
3295	
3296	    dict = shm_zone->data;
3297	
3298	    ngx_rwlock_wlock(&dict->sh->rwlock);
3299	
3300	    if (dict->timeout) {
3301	        ngx_js_dict_evict(dict, 0x7fffffff /* INT_MAX */);
3302	
3303	    } else {
3304	        rbtree = &dict->sh->rbtree;
3305	
3306	        if (rbtree->root == rbtree->sentinel) {
3307	            goto done;
3308	        }
3309	
3310	        for (rn = ngx_rbtree_min(rbtree->root, rbtree->sentinel);
3311	             rn != NULL;
3312	             rn = next)
3313	        {
3314	            next = ngx_rbtree_next(rbtree, rn);
3315	
3316	            ngx_rbtree_delete(rbtree, rn);
3317	
3318	            ngx_js_dict_node_free(dict, (ngx_js_dict_node_t *) rn);
3319	        }
3320	    }
3321	
3322	done:
3323	
3324	    dict->sh->dirty = 1;
3325	
3326	    ngx_rwlock_unlock(&dict->sh->rwlock);
3327	
3328	    if (dict->state_file.data && !dict->save_event.timer_set) {
3329	        ngx_add_timer(&dict->save_event, 1000);
3330	    }
3331	
3332	    return JS_UNDEFINED;
3333	}
