3468	        return JS_ThrowTypeError(cx, "\"this\" is not a shared dict");
3469	    }
3470	
3471	    dict = shm_zone->data;
3472	
3473	    if (dict->type != NGX_JS_DICT_TYPE_NUMBER) {
