3533	
3534	    shm_zone = JS_GetOpaque(this_val, NGX_QJS_CLASS_ID_SHARED_DICT);
3535	    if (shm_zone == NULL) {
3536	        return JS_ThrowTypeError(cx, "\"this\" is not a shared dict");
3537	    }
3538	
3539	    dict = shm_zone->data;
3540	
3541	    max_count = 1024;
3542	
3543	    if (argc > 0) {
3544	        if (JS_ToUint32(cx, &max_count, argv[0]) < 0) {
3545	            return JS_EXCEPTION;
3546	        }
3547	    }
3548	
3549	    rbtree = &dict->sh->rbtree;
3550	
3551	    now = 0;
3552	
3553	    if (dict->timeout) {
3554	        tp = ngx_timeofday();
3555	        now = tp->sec * 1000 + tp->msec;
3556	    }
3557	
3558	    ngx_rwlock_rlock(&dict->sh->rwlock);
3559	
3560	    if (rbtree->root == rbtree->sentinel) {
3561	        ngx_rwlock_unlock(&dict->sh->rwlock);
3562	        return JS_NewArray(cx);
3563	    }
3564	
3565	    arr = JS_NewArray(cx);
3566	    if (JS_IsException(arr)) {
3567	        ngx_rwlock_unlock(&dict->sh->rwlock);
3568	        return JS_EXCEPTION;
3569	    }
3570	
3571	    i = 0;
3572	
3573	    for (rn = ngx_rbtree_min(rbtree->root, rbtree->sentinel);
3574	         rn != NULL;
3575	         rn = ngx_rbtree_next(rbtree, rn))
3576	    {
3577	        node = (ngx_js_dict_node_t *) rn;
3578	
3579	        if (dict->timeout && now >= node->expire.key) {
3580	            continue;
3581	        }
3582	
3583	        if (max_count-- == 0) {
3584	            break;
3585	        }
3586	
3587	        kv = JS_NewArray(cx);
3588	        if (JS_IsException(kv)) {
3589	            ngx_rwlock_unlock(&dict->sh->rwlock);
3590	            JS_FreeValue(cx, arr);
3591	            return JS_EXCEPTION;
3592	        }
3593	
3594	        v = JS_NewStringLen(cx, (const char *) node->sn.str.data,
3595	                            node->sn.str.len);
3596	        if (JS_IsException(v)) {
3597	            ngx_rwlock_unlock(&dict->sh->rwlock);
3598	            JS_FreeValue(cx, kv);
3599	            JS_FreeValue(cx, arr);
3600	            return JS_EXCEPTION;
3601	        }
3602	
3603	        if (JS_DefinePropertyValueUint32(cx, kv, 0, v, JS_PROP_C_W_E) < 0) {
3604	            ngx_rwlock_unlock(&dict->sh->rwlock);
3605	            JS_FreeValue(cx, kv);
3606	            JS_FreeValue(cx, arr);
3607	            return JS_EXCEPTION;
3608	        }
3609	
3610	        v = ngx_qjs_dict_copy_value_locked(cx, dict, node);
3611	
3612	        if (JS_DefinePropertyValueUint32(cx, kv, 1, v, JS_PROP_C_W_E) < 0) {
3613	            ngx_rwlock_unlock(&dict->sh->rwlock);
3614	            JS_FreeValue(cx, kv);
3615	            JS_FreeValue(cx, arr);
3616	            return JS_EXCEPTION;
3617	        }
3618	
3619	        if (JS_DefinePropertyValueUint32(cx, arr, i++, kv, JS_PROP_C_W_E) < 0) {
3620	            ngx_rwlock_unlock(&dict->sh->rwlock);
3621	            JS_FreeValue(cx, arr);
3622	            return JS_EXCEPTION;
3623	        }
3624	    }
3625	
3626	    ngx_rwlock_unlock(&dict->sh->rwlock);
