3763	static JSValue
3764	ngx_qjs_ext_shared_dict_set(JSContext *cx, JSValueConst this_val,
3765	    int argc, JSValueConst *argv, int flags)
3766	{
3767	    JSValue          ret;
3768	    uint32_t         timeout;
3769	    ngx_str_t        key;
3770	    ngx_js_dict_t   *dict;
3771	    ngx_shm_zone_t  *shm_zone;
3772	
3773	    shm_zone = JS_GetOpaque(this_val, NGX_QJS_CLASS_ID_SHARED_DICT);
3774	    if (shm_zone == NULL) {
3775	        return JS_ThrowTypeError(cx, "\"this\" is not a shared dict");
3776	    }
3777	
3778	    dict = shm_zone->data;
3779	
3780	    if (dict->type == NGX_JS_DICT_TYPE_STRING) {
3781	        if (!JS_IsString(argv[1])) {
3782	            return JS_ThrowTypeError(cx, "string value is expected");
3783	        }
3784	
3785	    } else {
3786	        if (!JS_IsNumber(argv[1])) {
3787	            return JS_ThrowTypeError(cx, "number value is expected");
3788	        }
3789	    }
3790	
3791	    if (!JS_IsUndefined(argv[2])) {
3792	        if (!JS_IsNumber(argv[2])) {
3793	            return JS_ThrowTypeError(cx, "timeout is not a number");
3794	        }
3795	
3796	        if (!dict->timeout) {
3797	            return JS_ThrowTypeError(cx,
3798	                                "shared dict must be declared with timeout");
3799	        }
3800	
3801	        if (JS_ToUint32(cx, &timeout, argv[2]) < 0) {
3802	            return JS_EXCEPTION;
3803	        }
3804	
3805	        if (timeout < 1) {
3806	            return JS_ThrowTypeError(cx,
3807	                                "timeout must be greater than or equal to 1");
3808	        }
3809	
3810	    } else {
3811	        timeout = dict->timeout;
3812	    }
3813	
3814	    key.data = (u_char *) JS_ToCStringLen(cx, &key.len, argv[0]);
3815	    if (key.data == NULL) {
3816	        return JS_EXCEPTION;
3817	    }
3818	
3819	    ret = ngx_qjs_dict_set(cx, shm_zone->data, &key, argv[1], timeout, flags);
3820	    if (JS_IsException(ret)) {
3821	        goto done;
3822	    }
3823	
3824	    if (flags) {
3825	        /* add() or replace(). */
3826	        goto done;
3827	    }
3828	
3829	    JS_FreeValue(cx, ret);
3830	    ret = JS_DupValue(cx, this_val);
3831	
3832	done:
3833	
3834	    JS_FreeCString(cx, (char *) key.data);
3835	
3836	    return ret;
3837	}
