3840	static JSValue
3841	ngx_qjs_ext_shared_dict_size(JSContext *cx, JSValueConst this_val,
3842	    int argc, JSValueConst *argv)
3843	{
3844	    njs_int_t            items;
3845	    ngx_msec_t           now;
3846	    ngx_time_t          *tp;
3847	    ngx_rbtree_t        *rbtree;
3848	    ngx_js_dict_t       *dict;
3849	    ngx_shm_zone_t      *shm_zone;
3850	    ngx_rbtree_node_t   *rn;
3851	    ngx_js_dict_node_t  *node;
3852	
3853	    shm_zone = JS_GetOpaque(this_val, NGX_QJS_CLASS_ID_SHARED_DICT);
3854	    if (shm_zone == NULL) {
3855	        return JS_ThrowTypeError(cx, "\"this\" is not a shared dict");
3856	    }
3857	
3858	    dict = shm_zone->data;
3859	
3860	    now = 0;
3861	
3862	    if (dict->timeout) {
3863	        tp = ngx_timeofday();
3864	        now = tp->sec * 1000 + tp->msec;
3865	    }
3866	
3867	    ngx_rwlock_rlock(&dict->sh->rwlock);
3868	
3869	    rbtree = &dict->sh->rbtree;
3870	
3871	    if (rbtree->root == rbtree->sentinel) {
3872	        ngx_rwlock_unlock(&dict->sh->rwlock);
3873	        return JS_NewInt32(cx, 0);
3874	    }
3875	
3876	    items = 0;
3877	
3878	    for (rn = ngx_rbtree_min(rbtree->root, rbtree->sentinel);
3879	         rn != NULL;
3880	         rn = ngx_rbtree_next(rbtree, rn))
3881	    {
3882	        node = (ngx_js_dict_node_t *) rn;
3883	
3884	        if (dict->timeout && now >= node->expire.key) {
3885	            continue;
3886	        }
3887	
3888	        items++;
3889	    }
3890	
3891	    ngx_rwlock_unlock(&dict->sh->rwlock);
3892	
3893	    return JS_NewInt32(cx, items);
3894	}
