4019	        /* GCC complains about uninitialized entry.str.data. */
4020	        entry.str.data = NULL;
4021	
4022	        if (JS_ToFloat64(cx, &entry.number, value) < 0) {
4023	            return NGX_ERROR;
4024	        }
4025	    }
4026	
4027	    rc = ngx_js_dict_add_value(dict, key, &entry, timeout, now);
