4037	static JSValue
4038	ngx_qjs_dict_delete(JSContext *cx, ngx_js_dict_t *dict, ngx_str_t *key,
4039	    int retval)
4040	{
4041	    JSValue              ret;
4042	    ngx_msec_t           now;
4043	    ngx_time_t          *tp;
4044	    ngx_js_dict_node_t  *node;
4045	
4046	    ngx_rwlock_wlock(&dict->sh->rwlock);
4047	
4048	    node = ngx_qjs_dict_lookup(dict, key);
4049	
4050	    if (node == NULL) {
4051	        ngx_rwlock_unlock(&dict->sh->rwlock);
4052	        return JS_UNDEFINED;
4053	    }
4054	
4055	    if (dict->timeout) {
4056	        ngx_rbtree_delete(&dict->sh->rbtree_expire, &node->expire);
4057	    }
4058	
4059	    ngx_rbtree_delete(&dict->sh->rbtree, (ngx_rbtree_node_t *) node);
4060	
4061	    if (retval) {
4062	        tp = ngx_timeofday();
4063	        now = tp->sec * 1000 + tp->msec;
4064	
4065	        if (!dict->timeout || now < node->expire.key) {
4066	            ret = ngx_qjs_dict_copy_value_locked(cx, dict, node);
4067	
4068	        } else {
4069	            ret = JS_UNDEFINED;
4070	        }
4071	
4072	    } else {
4073	        ret = JS_TRUE;
4074	    }
4075	
4076	    ngx_js_dict_node_free(dict, node);
4077	
4078	    dict->sh->dirty = 1;
4079	
4080	    ngx_rwlock_unlock(&dict->sh->rwlock);
4081	
4082	    if (dict->state_file.data && !dict->save_event.timer_set) {
4083	        ngx_add_timer(&dict->save_event, 1000);
4084	    }
4085	
4086	    return ret;
4087	}
