4128	static JSValue
4129	ngx_qjs_dict_incr(JSContext *cx, ngx_js_dict_t *dict, ngx_str_t *key,
4130	    double delta, double init, ngx_msec_t timeout)
4131	{
4132	    JSValue              value;
4133	    ngx_msec_t           now;
4134	    ngx_time_t          *tp;
4135	    ngx_js_dict_node_t  *node;
4136	
4137	    tp = ngx_timeofday();
4138	    now = tp->sec * 1000 + tp->msec;
4139	
4140	    ngx_rwlock_wlock(&dict->sh->rwlock);
4141	
4142	    node = ngx_qjs_dict_lookup(dict, key);
4143	
4144	    if (node == NULL) {
4145	        value = JS_NewFloat64(cx, init + delta);
4146	        if (ngx_qjs_dict_add(cx, dict, key, value,
4147	                              timeout ? timeout : dict->timeout, now)
4148	            != NGX_OK)
4149	        {
4150	            ngx_rwlock_unlock(&dict->sh->rwlock);
4151	            JS_FreeValue(cx, value);
4152	            return ngx_qjs_throw_shared_memory_error(cx);
4153	        }
4154	
4155	    } else {
4156	        node->value.number += delta;
4157	        value = JS_NewFloat64(cx, node->value.number);
4158	
4159	        if (dict->timeout && timeout) {
4160	            ngx_rbtree_delete(&dict->sh->rbtree_expire, &node->expire);
4161	            node->expire.key = now + timeout;
4162	            ngx_rbtree_insert(&dict->sh->rbtree_expire, &node->expire);
4163	        }
4164	    }
4165	
4166	    dict->sh->dirty = 1;
4167	
4168	    ngx_rwlock_unlock(&dict->sh->rwlock);
4169	
4170	    if (dict->state_file.data && !dict->save_event.timer_set) {
4171	        ngx_add_timer(&dict->save_event, 1000);
4172	    }
4173	
4174	    return value;
4175	}
