4178	static JSValue
4179	ngx_qjs_dict_set(JSContext *cx, ngx_js_dict_t *dict, ngx_str_t *key,
4180	    JSValue value, ngx_msec_t timeout, unsigned flags)
4181	{
4182	    ngx_msec_t           now;
4183	    ngx_time_t          *tp;
4184	    ngx_js_dict_node_t  *node;
4185	
4186	    tp = ngx_timeofday();
4187	    now = tp->sec * 1000 + tp->msec;
4188	
4189	    ngx_rwlock_wlock(&dict->sh->rwlock);
4190	
4191	    node = ngx_qjs_dict_lookup(dict, key);
4192	
4193	    if (node == NULL) {
4194	        if (flags & NGX_JS_DICT_FLAG_MUST_EXIST) {
4195	            ngx_rwlock_unlock(&dict->sh->rwlock);
4196	            return JS_FALSE;
4197	        }
4198	
4199	        if (ngx_qjs_dict_add(cx, dict, key, value, timeout, now) != NGX_OK) {
4200	            goto memory_error;
4201	        }
4202	
4203	    } else {
4204	
4205	        if (flags & NGX_JS_DICT_FLAG_MUST_NOT_EXIST) {
4206	            if (!dict->timeout || now < node->expire.key) {
4207	                ngx_rwlock_unlock(&dict->sh->rwlock);
4208	                return JS_FALSE;
4209	            }
4210	        }
4211	
4212	        if (ngx_qjs_dict_update(cx, dict, node, value, timeout, now)
4213	            != NGX_OK)
4214	        {
4215	            goto memory_error;
4216	        }
4217	    }
4218	
4219	    dict->sh->dirty = 1;
4220	
4221	    ngx_rwlock_unlock(&dict->sh->rwlock);
4222	
4223	    if (dict->state_file.data && !dict->save_event.timer_set) {
4224	        ngx_add_timer(&dict->save_event, 1000);
4225	    }
4226	
4227	    return JS_TRUE;
4228	
4229	memory_error:
4230	
4231	    ngx_rwlock_unlock(&dict->sh->rwlock);
4232	
4233	    return ngx_qjs_throw_shared_memory_error(cx);
4234	}
