4236	
4237	static ngx_int_t
4238	ngx_qjs_dict_update(JSContext *cx, ngx_js_dict_t *dict,
4239	    ngx_js_dict_node_t *node, JSValue value, ngx_msec_t timeout, ngx_msec_t now)
4240	{
4241	    u_char     *p;
4242	    ngx_str_t   string;
4243	
4244	    if (dict->timeout) {
4245	        /*
4246	         * Remove the node from the expire tree before allocating
4247	         * memory for the new value.  This serves two purposes:
4248	         * it prevents ngx_js_dict_evict() from freeing this node
4249	         * during allocation, and it allows the node to be reinserted
4250	         * with the updated expiry time below.
4251	         */
4252	        ngx_rbtree_delete(&dict->sh->rbtree_expire, &node->expire);
4253	    }
4254	
4255	    if (dict->type == NGX_JS_DICT_TYPE_STRING) {
4256	        string.data = (u_char *) JS_ToCStringLen(cx, &string.len, value);
4257	        if (string.data == NULL) {
4258	            if (dict->timeout) {
4259	                ngx_rbtree_insert(&dict->sh->rbtree_expire, &node->expire);
4260	            }
4261	
4262	            return NGX_ERROR;
4263	        }
4264	
4265	        p = ngx_js_dict_alloc(dict, string.len);
4266	        if (p == NULL) {
4267	            JS_FreeCString(cx, (char *) string.data);
4268	
4269	            if (dict->timeout) {
4270	                ngx_rbtree_insert(&dict->sh->rbtree_expire, &node->expire);
4271	            }
4272	
4273	            return NGX_ERROR;
4274	        }
4275	
4276	        ngx_slab_free_locked(dict->shpool, node->value.str.data);
4277	        ngx_memcpy(p, string.data, string.len);
4278	
4279	        node->value.str.data = p;
4280	        node->value.str.len = string.len;
4281	
4282	        JS_FreeCString(cx, (char *) string.data);
4283	
4284	    } else {
4285	        if (JS_ToFloat64(cx, &node->value.number, value) < 0) {
4286	            if (dict->timeout) {
4287	                ngx_rbtree_insert(&dict->sh->rbtree_expire, &node->expire);
4288	            }
4289	
4290	            return NGX_ERROR;
4291	        }
4292	    }
4293	
4294	    if (dict->timeout) {
4295	        node->expire.key = now + timeout;
4296	        ngx_rbtree_insert(&dict->sh->rbtree_expire, &node->expire);
4297	    }
4298	
4299	    return NGX_OK;
4300	}
