4303	static JSValue
4304	ngx_qjs_shared_dict_error_constructor(JSContext *cx, JSValueConst this_val,
4305	    int argc, JSValueConst *argv)
4306	{
4307	    JSValue  proto, error_ctor, result, global_obj;
4308	
4309	    global_obj = JS_GetGlobalObject(cx);
4310	
4311	    error_ctor = JS_GetPropertyStr(cx, global_obj, "Error");
4312	    if (JS_IsException(error_ctor)) {
4313	        JS_FreeValue(cx, global_obj);
4314	        return error_ctor;
4315	    }
4316	
4317	    result = JS_CallConstructor(cx, error_ctor, argc, argv);
4318	    JS_FreeValue(cx, error_ctor);
4319	    JS_FreeValue(cx, global_obj);
4320	
4321	    if (!JS_IsException(result)) {
4322	        proto = JS_GetClassProto(cx, NGX_QJS_CLASS_ID_SHARED_DICT_ERROR);
4323	        if (JS_SetPrototype(cx, result, proto) < 0) {
4324	            JS_FreeValue(cx, result);
4325	            JS_FreeValue(cx, proto);
4326	            return JS_EXCEPTION;
4327	        }
4328	
4329	        JS_FreeValue(cx, proto);
4330	    }
4331	
4332	    return result;
4333	}
