4335	
4336	static JSValue
4337	ngx_qjs_throw_shared_memory_error(JSContext *cx)
4338	{
4339	    JSValue  ctor, global_obj, err;
4340	
4341	    global_obj = JS_GetGlobalObject(cx);
4342	
